where the remainders are bounded by:
\begin{align*}
     |\mathbf{R}_1| &\le \frac{3 |\mathbf{w}|^2}{\left( \min_{t \in [0,1]} |\mathbf{v} + t\mathbf{w}| \right)^2}, \\
     |\mathbf{R}_2| &\le \frac{6 |\mathbf{w}|^3}{\left( \min_{t \in [0,1]} |\mathbf{v} + t\mathbf{w}| \right)^3}.
\end{align*}
\end{lemma}

